#!/usr/bin/env python3
r"""
B13 — Bind sticky story to real map layers.

Run from repository root:

  python scripts\21_bind_sticky_story_to_real_layers.py
"""

from pathlib import Path
import datetime

TODAY = datetime.date.today().isoformat()
STORY_LAYERS_JS = '/*\nB13 — Bind sticky story to real map layers where available.\n\nAvailable real layers:\n- world country base layer\n- country drained-organic-soils hotspot layer\n- Baden-Württemberg BK50-Moor layer\n\nPlanned/future layers are explicitly labelled as placeholders.\nNo external dependencies.\n*/\n\n(function () {\n  const URLS = {\n    base: "public/data/world_countries_110m_base.geojson",\n    hotspots: "public/data/hotspot_countries_110m.geojson",\n    bw: "public/data/bw_bk50_moor_simplified.geojson"\n  };\n\n  const WIDTH = 960;\n  const HEIGHT = 620;\n  const PAD = 36;\n  const cache = {};\n  const htmlCache = {};\n\n  const stage = document.querySelector("#storyStage");\n  if (!stage) return;\n\n  function num(value) {\n    if (value === undefined || value === null || value === "") return null;\n    const n = Number(String(value).replace(",", "."));\n    return Number.isFinite(n) ? n : null;\n  }\n\n  function fmtKt(value) {\n    const n = num(value);\n    if (n === null) return "no data";\n    if (n >= 1000) return `${(n / 1000).toFixed(1)} Mt CO₂e`;\n    return `${Math.round(n)} kt CO₂e`;\n  }\n\n  function fmtArea(value) {\n    const n = num(value);\n    if (n === null) return "area not available";\n    const ha = n / 10000;\n    if (ha >= 1000) return `${(ha / 1000).toFixed(1)} kha`;\n    return `${ha.toFixed(1)} ha`;\n  }\n\n  async function fetchJSON(url) {\n    const res = await fetch(url);\n    if (!res.ok) throw new Error(`Failed to load ${url}`);\n    return res.json();\n  }\n\n  function robinsonProject(coord) {\n    const lon = Math.max(-180, Math.min(180, Number(coord[0]) || 0));\n    const lat = Math.max(-90, Math.min(90, Number(coord[1]) || 0));\n    const absLat = Math.abs(lat);\n\n    const X = [\n      1.0000, 0.9986, 0.9954, 0.9900, 0.9822, 0.9730, 0.9600,\n      0.9427, 0.9216, 0.8962, 0.8679, 0.8350, 0.7986, 0.7597,\n      0.7186, 0.6732, 0.6213, 0.5722, 0.5322\n    ];\n\n    const Y = [\n      0.0000, 0.0620, 0.1240, 0.1860, 0.2480, 0.3100, 0.3720,\n      0.4340, 0.4958, 0.5571, 0.6176, 0.6769, 0.7346, 0.7903,\n      0.8435, 0.8936, 0.9394, 0.9761, 1.0000\n    ];\n\n    const i = Math.min(17, Math.floor(absLat / 5));\n    const t = (absLat - i * 5) / 5;\n    const xCoef = X[i] + (X[i + 1] - X[i]) * t;\n    const yCoef = Y[i] + (Y[i + 1] - Y[i]) * t;\n\n    const lonRad = lon * Math.PI / 180;\n    const sign = lat < 0 ? -1 : 1;\n    const rawX = 0.8487 * xCoef * lonRad;\n    const rawY = 1.3523 * yCoef * sign;\n    const maxX = 0.8487 * Math.PI;\n    const maxY = 1.3523;\n\n    const x = (0.5 + rawX / (2 * maxX)) * WIDTH;\n    const y = (0.5 - rawY / (2 * maxY)) * HEIGHT;\n    return [x, y];\n  }\n\n  function collectCoords(coords, out) {\n    if (!Array.isArray(coords)) return;\n    if (coords.length >= 2 && typeof coords[0] === "number" && typeof coords[1] === "number") {\n      out.push(coords);\n      return;\n    }\n    coords.forEach(item => collectCoords(item, out));\n  }\n\n  function bbox(features) {\n    const pts = [];\n    features.forEach(f => collectCoords(f.geometry?.coordinates, pts));\n    if (!pts.length) return null;\n    const xs = pts.map(p => p[0]);\n    const ys = pts.map(p => p[1]);\n    return { minX: Math.min(...xs), minY: Math.min(...ys), maxX: Math.max(...xs), maxY: Math.max(...ys) };\n  }\n\n  function makeBBoxProject(features) {\n    const bounds = bbox(features);\n    if (!bounds) return coord => [0, 0];\n\n    const dx = bounds.maxX - bounds.minX;\n    const dy = bounds.maxY - bounds.minY;\n    const sx = (WIDTH - PAD * 2) / dx;\n    const sy = (HEIGHT - PAD * 2) / dy;\n    const s = Math.min(sx, sy);\n    const usedW = dx * s;\n    const usedH = dy * s;\n    const ox = (WIDTH - usedW) / 2;\n    const oy = (HEIGHT - usedH) / 2;\n\n    return function project(coord) {\n      const x = ox + (coord[0] - bounds.minX) * s;\n      const y = HEIGHT - (oy + (coord[1] - bounds.minY) * s);\n      return [x, y];\n    };\n  }\n\n  function ringToPath(ring, project) {\n    if (!ring || !ring.length) return "";\n    return ring.map((coord, idx) => {\n      const [x, y] = project(coord);\n      return `${idx === 0 ? "M" : "L"}${x.toFixed(2)},${y.toFixed(2)}`;\n    }).join(" ") + " Z";\n  }\n\n  function geometryToPath(geometry, project) {\n    if (!geometry) return "";\n    if (geometry.type === "Polygon") {\n      return geometry.coordinates.map(ring => ringToPath(ring, project)).join(" ");\n    }\n    if (geometry.type === "MultiPolygon") {\n      return geometry.coordinates\n        .flatMap(poly => poly.map(ring => ringToPath(ring, project)))\n        .join(" ");\n    }\n    return "";\n  }\n\n  function quantileBreaks(values) {\n    const sorted = values.filter(v => Number.isFinite(v)).sort((a, b) => a - b);\n    if (!sorted.length) return [];\n    const q = p => sorted[Math.max(0, Math.min(sorted.length - 1, Math.round((sorted.length - 1) * p)))];\n    return [q(0.2), q(0.4), q(0.6), q(0.8)];\n  }\n\n  function fillClass(value, breaks) {\n    const v = num(value);\n    if (v === null || !breaks.length) return "story-hotspot-no-data";\n    if (v <= breaks[0]) return "story-hotspot-1";\n    if (v <= breaks[1]) return "story-hotspot-2";\n    if (v <= breaks[2]) return "story-hotspot-3";\n    if (v <= breaks[3]) return "story-hotspot-4";\n    return "story-hotspot-5";\n  }\n\n  function worldBasePaths() {\n    const features = cache.base?.features || [];\n    return features.map(f => `<path class="story-real-base-country" d="${geometryToPath(f.geometry, robinsonProject)}"></path>`).join("");\n  }\n\n  function renderWorldEmissions() {\n    const hotspots = cache.hotspots?.features || [];\n    const values = hotspots.map(f => num(f.properties?.emissions_total_kt_co2e)).filter(v => v !== null);\n    const breaks = quantileBreaks(values);\n\n    const hotspotPaths = hotspots.map(f => {\n      const props = f.properties || {};\n      const klass = fillClass(props.emissions_total_kt_co2e, breaks);\n      const label = `${props.country || "Country"} · ${fmtKt(props.emissions_total_kt_co2e)}`;\n      return `<path class="story-real-hotspot ${klass}" d="${geometryToPath(f.geometry, robinsonProject)}">\n        <title>${label}</title>\n      </path>`;\n    }).join("");\n\n    return `\n      <svg class="story-real-svg" viewBox="0 0 ${WIDTH} ${HEIGHT}" preserveAspectRatio="xMidYMid meet">\n        <rect class="story-real-ocean" x="0" y="0" width="${WIDTH}" height="${HEIGHT}"></rect>\n        ${worldBasePaths()}\n        ${hotspotPaths}\n      </svg>\n      <div class="story-real-caption">\n        <strong>Real layer:</strong> country-level drained organic soils emissions · <span>public/data/hotspot_countries_110m.geojson</span>\n      </div>\n    `;\n  }\n\n  function renderPlannedGlobalPeat() {\n    return `\n      <svg class="story-real-svg" viewBox="0 0 ${WIDTH} ${HEIGHT}" preserveAspectRatio="xMidYMid meet">\n        <rect class="story-real-ocean" x="0" y="0" width="${WIDTH}" height="${HEIGHT}"></rect>\n        ${worldBasePaths()}\n        <ellipse class="story-planned-peat" cx="440" cy="170" rx="60" ry="17"></ellipse>\n        <ellipse class="story-planned-peat" cx="530" cy="185" rx="82" ry="22"></ellipse>\n        <ellipse class="story-planned-peat" cx="385" cy="250" rx="52" ry="18"></ellipse>\n        <ellipse class="story-planned-peat" cx="650" cy="285" rx="70" ry="20"></ellipse>\n      </svg>\n      <div class="story-real-caption planned">\n        <strong>Planned layer:</strong> global peat/organic-soils extent · source inventory prepared, web layer not processed yet\n      </div>\n    `;\n  }\n\n  function renderEuropeOrGermany(state) {\n    const isGermany = state === "germany";\n    const box = isGermany\n      ? { x: 500, y: 245, w: 32, h: 38, label: "Germany organic-soils bridge layer planned" }\n      : { x: 445, y: 180, w: 205, h: 155, label: "Europe wetland/peat context planned" };\n\n    return `\n      <svg class="story-real-svg" viewBox="0 0 ${WIDTH} ${HEIGHT}" preserveAspectRatio="xMidYMid meet">\n        <rect class="story-real-ocean" x="0" y="0" width="${WIDTH}" height="${HEIGHT}"></rect>\n        ${worldBasePaths()}\n        <rect class="story-focus-box" x="${box.x}" y="${box.y}" width="${box.w}" height="${box.h}" rx="14"></rect>\n        <text class="story-focus-label" x="${box.x + box.w + 12}" y="${box.y + 24}">${isGermany ? "Germany" : "Europe"}</text>\n      </svg>\n      <div class="story-real-caption planned">\n        <strong>Planned layer:</strong> ${box.label}\n      </div>\n    `;\n  }\n\n  function renderBW() {\n    const features = (cache.bw?.features || []).filter(f => f.geometry);\n    const project = makeBBoxProject(features);\n\n    const paths = features.map((f, idx) => {\n      const props = f.properties || {};\n      const typeIdx = idx % 7;\n      const title = `${props.class || "BK50-Moor"} · ${props.soil || ""} · ${fmtArea(props.source_area_m2)}`;\n      return `<path class="story-bw-moor story-bw-type-${typeIdx}" d="${geometryToPath(f.geometry, project)}">\n        <title>${title}</title>\n      </path>`;\n    }).join("");\n\n    return `\n      <svg class="story-real-svg" viewBox="0 0 ${WIDTH} ${HEIGHT}" preserveAspectRatio="xMidYMid meet">\n        <rect class="story-real-ocean" x="0" y="0" width="${WIDTH}" height="${HEIGHT}"></rect>\n        ${paths}\n      </svg>\n      <div class="story-real-caption">\n        <strong>Real layer:</strong> Baden-Württemberg BK50-Moor simplified web layer · <span>${features.length.toLocaleString("en-US")} polygons</span>\n      </div>\n    `;\n  }\n\n  function renderBoundary() {\n    return `\n      <div class="story-boundary-panel">\n        <p class="eyebrow">Interpretation boundary</p>\n        <h3>Extent is not suitability</h3>\n        <p>\n          Peat/organic-soil extent is necessary spatial context. Rewetting suitability would also need hydrology,\n          current land use, drainage, ownership, farm economics, policy instruments and local feasibility.\n        </p>\n      </div>\n    `;\n  }\n\n  function ensureContainer() {\n    let container = document.querySelector("#storyRealLayerMap");\n    if (container) return container;\n\n    container = document.createElement("div");\n    container.id = "storyRealLayerMap";\n    container.className = "story-real-map";\n\n    const label = stage.querySelector(".story-state-label");\n    if (label) {\n      stage.insertBefore(container, label);\n    } else {\n      stage.appendChild(container);\n    }\n\n    stage.classList.add("real-story-bound");\n    return container;\n  }\n\n  function renderState(state) {\n    const container = ensureContainer();\n    const key = state || "world-emissions";\n\n    if (!htmlCache[key]) {\n      if (key === "world-emissions") htmlCache[key] = renderWorldEmissions();\n      else if (key === "global-peat") htmlCache[key] = renderPlannedGlobalPeat();\n      else if (key === "europe" || key === "germany") htmlCache[key] = renderEuropeOrGermany(key);\n      else if (key === "bw") htmlCache[key] = renderBW();\n      else if (key === "boundary") htmlCache[key] = renderBoundary();\n      else htmlCache[key] = renderWorldEmissions();\n    }\n\n    container.innerHTML = htmlCache[key];\n  }\n\n  async function init() {\n    const container = ensureContainer();\n    container.innerHTML = `<div class="map-loading">Loading real story layers…</div>`;\n\n    const [base, hotspots, bw] = await Promise.allSettled([\n      fetchJSON(URLS.base),\n      fetchJSON(URLS.hotspots),\n      fetchJSON(URLS.bw)\n    ]);\n\n    if (base.status === "fulfilled") cache.base = base.value;\n    if (hotspots.status === "fulfilled") cache.hotspots = hotspots.value;\n    if (bw.status === "fulfilled") cache.bw = bw.value;\n\n    if (!cache.base || !cache.hotspots || !cache.bw) {\n      container.innerHTML = `\n        <div class="map-loading">\n          Some real story layers could not be loaded. Check public/data files.\n        </div>\n      `;\n      console.warn("Story layer loading status:", { base, hotspots, bw });\n      return;\n    }\n\n    renderState(stage.dataset.state || "world-emissions");\n\n    const observer = new MutationObserver(() => {\n      renderState(stage.dataset.state || "world-emissions");\n    });\n\n    observer.observe(stage, { attributes: true, attributeFilter: ["data-state"] });\n  }\n\n  if (document.readyState === "loading") {\n    document.addEventListener("DOMContentLoaded", init);\n  } else {\n    init();\n  }\n})();\n'
CSS_APPEND = '\n/* B13 bind sticky story to real map layers */\n.story-stage.real-story-bound .story-layer,\n.story-stage.real-story-bound .story-state-label {\n  display: none;\n}\n\n.story-real-map {\n  position: absolute;\n  inset: 0;\n  z-index: 3;\n}\n\n.story-real-svg {\n  display: block;\n  width: 100%;\n  height: 100%;\n}\n\n.story-real-ocean {\n  fill: rgba(14, 24, 22, .96);\n}\n\n.story-real-base-country {\n  fill: rgba(91, 108, 93, .34);\n  stroke: rgba(8, 15, 13, .74);\n  stroke-width: .38;\n}\n\n.story-real-hotspot {\n  stroke: rgba(8,15,13,.9);\n  stroke-width: .5;\n  opacity: .95;\n}\n\n.story-hotspot-no-data { fill: rgba(91,108,93,.28); }\n.story-hotspot-1 { fill: rgba(88,125,117,.58); }\n.story-hotspot-2 { fill: rgba(111,146,124,.66); }\n.story-hotspot-3 { fill: rgba(165,172,105,.76); }\n.story-hotspot-4 { fill: rgba(204,160,91,.80); }\n.story-hotspot-5 { fill: rgba(202,112,82,.84); }\n\n.story-planned-peat {\n  fill: rgba(75, 145, 108, .42);\n  stroke: rgba(132, 202, 161, .70);\n  stroke-width: 1.2;\n  filter: blur(.2px);\n}\n\n.story-focus-box {\n  fill: rgba(212,196,118,.10);\n  stroke: rgba(232,222,159,.88);\n  stroke-width: 2.2;\n  stroke-dasharray: 6 4;\n}\n\n.story-focus-label {\n  fill: rgba(232,222,159,.96);\n  font-size: 20px;\n  font-weight: 800;\n  paint-order: stroke;\n  stroke: rgba(8,15,13,.95);\n  stroke-width: 4px;\n  stroke-linejoin: round;\n}\n\n.story-bw-moor {\n  stroke: rgba(18,27,24,.78);\n  stroke-width: .35;\n  opacity: .84;\n}\n\n.story-bw-type-0 { fill: rgba(75, 120, 96, .70); }\n.story-bw-type-1 { fill: rgba(108, 141, 101, .70); }\n.story-bw-type-2 { fill: rgba(139, 124, 87, .74); }\n.story-bw-type-3 { fill: rgba(92, 111, 132, .70); }\n.story-bw-type-4 { fill: rgba(159, 128, 96, .74); }\n.story-bw-type-5 { fill: rgba(119, 103, 139, .70); }\n.story-bw-type-6 { fill: rgba(149, 158, 111, .70); }\n\n.story-real-caption {\n  position: absolute;\n  left: 1rem;\n  right: 1rem;\n  bottom: 1rem;\n  border: 1px solid rgba(255,255,255,.10);\n  border-radius: .85rem;\n  padding: .7rem .85rem;\n  background: rgba(7,12,11,.76);\n  color: var(--muted);\n  backdrop-filter: blur(6px);\n}\n\n.story-real-caption strong {\n  color: var(--text);\n}\n\n.story-real-caption.planned {\n  border-color: rgba(212,196,118,.24);\n  background: rgba(48,43,25,.70);\n}\n\n.story-boundary-panel {\n  position: absolute;\n  inset: 18% 12%;\n  display: grid;\n  align-content: center;\n  border: 1px dashed rgba(232,222,159,.55);\n  border-radius: 1.2rem;\n  padding: 2rem;\n  background: rgba(212,196,118,.06);\n}\n\n.story-boundary-panel h3 {\n  margin: .25rem 0 .65rem;\n}\n\n@media (max-width: 980px) {\n  .story-real-map {\n    position: relative;\n    min-height: 440px;\n  }\n\n  .story-real-caption {\n    position: relative;\n    left: auto;\n    right: auto;\n    bottom: auto;\n    margin: .75rem;\n  }\n}\n'
METHOD = '# B13 — Bind Sticky Story to Real Map Layers\n\nDate: 2026-06-18\n\n## Purpose\n\nConnect the sticky-scroll scaffold to available real atlas layers.\n\n## Real layers used\n\n- `public/data/world_countries_110m_base.geojson`\n- `public/data/hotspot_countries_110m.geojson`\n- `public/data/bw_bk50_moor_simplified.geojson`\n\n## Bound story states\n\n| Scroll state | Layer status |\n|---|---|\n| World emissions | Real country-level hotspot layer |\n| Global peat/organic soils | Placeholder, labelled as planned |\n| Europe | Placeholder, labelled as planned |\n| Germany | Placeholder, labelled as planned |\n| Baden-Württemberg | Real BK50-Moor simplified layer |\n| Interpretation boundary | Real caveat panel |\n\n## Design decision\n\nThe story now clearly distinguishes available real data from planned future layers. It does not pretend that global, European or Germany peat/organic-soils layers have already been processed.\n\n## Next step\n\nProcess the next missing real layer. Recommended order:\n\n1. Germany organic-soils kulisse,\n2. European Wetland Map,\n3. global peat/organic-soils layer.\n'
TASK = '# Task B14 — Process Germany Organic-Soils Layer\n\n## Agent\n\nData & GIS Agent + Visualization Engineer Agent + QA Critic Agent\n\n## Goal\n\nBuild the next real spatial layer for the sticky-scroll sequence: Germany organic soils.\n\n## Rationale\n\nThe sticky story currently has real layers for:\n\n- world country emissions,\n- Baden-Württemberg BK50-Moor.\n\nThe Germany step is still a labelled placeholder. A national organic-soils layer would bridge the country hotspot map and the Baden-Württemberg regional zoom.\n\n## Candidate source\n\nAktualisierte Kulisse organischer Böden in Deutschland, Thünen / OpenAgrar.\n\n## Expected workflow\n\n1. Download raw data manually to `data/external/peat_soils/germany_organic_soils/`.\n2. Inspect format, CRS, attributes and license.\n3. Export/reproject to WGS84 GeoJSON if needed.\n4. Simplify geometry for web display.\n5. Export to `public/data/germany_organic_soils_simplified.geojson`.\n6. Add method note and attribution.\n\n## Acceptance criteria\n\n- raw files are not committed,\n- public GeoJSON is small enough for GitHub Pages,\n- layer class meanings are documented,\n- sticky story Germany step uses the real layer,\n- caveat remains visible.\n'

def read(path: Path) -> str:
    return path.read_text(encoding="utf-8")

def write(path: Path, text: str):
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(text, encoding="utf-8")

def main():
    root = Path.cwd()
    index = root / "index.html"

    required = [
        root / "public" / "data" / "world_countries_110m_base.geojson",
        root / "public" / "data" / "hotspot_countries_110m.geojson",
        root / "public" / "data" / "bw_bk50_moor_simplified.geojson",
    ]

    if not index.exists():
        raise SystemExit("Run from repository root. index.html not found.")

    for path in required:
        if not path.exists():
            raise SystemExit(f"Required public data layer missing: {path}")

    write(root / "src" / "scrolly_story_layers.js", STORY_LAYERS_JS)

    html = read(index)
    if 'src="src/scrolly_story_layers.js"' not in html:
        marker = '<script src="src/scrolly_story.js"></script>'
        if marker in html:
            html = html.replace(marker, marker + '\n  <script src="src/scrolly_story_layers.js"></script>')
        elif "</body>" in html:
            html = html.replace("</body>", '  <script src="src/scrolly_story_layers.js"></script>\n</body>')
        else:
            raise SystemExit("Could not insert scrolly_story_layers.js script tag.")
        write(index, html)

    styles = root / "src" / "styles.css"
    css = read(styles)
    if "B13 bind sticky story to real map layers" not in css:
        write(styles, css + "\n" + CSS_APPEND)

    write(root / "docs" / "B13_bind_sticky_story_to_real_layers.md", METHOD)
    write(root / "tasks" / "B14_process_germany_organic_soils_layer.md", TASK)

    done = root / "tasks" / "done.md"
    done_text = read(done) if done.exists() else "# Done\n"
    if "Task B13 completed" not in done_text:
        done_text += f"- {TODAY}: Task B13 completed — bound sticky story to real world emissions and Baden-Württemberg BK50-Moor layers.\n"
        write(done, done_text)

    print("B13 sticky story real-layer binding applied.")
    print("Changed/created:")
    print("  index.html")
    print("  src/scrolly_story_layers.js")
    print("  src/styles.css")
    print("  docs/B13_bind_sticky_story_to_real_layers.md")
    print("  tasks/B14_process_germany_organic_soils_layer.md")
    print("  tasks/done.md")
    print()
    print("Local test:")
    print("  python -m http.server 8000")
    print("  open http://localhost:8000")
    print("  hard reload with Ctrl+F5")

if __name__ == "__main__":
    main()
